#include <bits/stdc++.h>
using namespace std;
map<string,bool> a;
string s1,s2;
int main(){
	cin>>s1>>s2;
	string tmp;
	for(int i=0;i<s1.size();i++){
		tmp=tmp+s1[i];
		a[tmp]=true;
	}
	tmp="";
	for(int i=s1.size()-1;i>=0;i--){
		tmp=s1[i]+tmp;
		a[tmp]=true;
	}
	tmp="";
	int ans=0;
	for(int i=0;i<s2.size();i++){
		tmp=tmp+s2[i];
		if(a[tmp]==true)ans=max(ans,i+1);
	}
	tmp="";
	for(int i=s2.size()-1;i>=0;i--){
		tmp=s2[i]+tmp;
		if(a[tmp]==true)ans=max(ans,int(s2.size())-i);
	}
	cout<<ans;
	return 0;
}
